SELECT config_id, version_id, scope_id
FROM detector_data
WHERE config_id > 10;

SELECT AVG(value) AS average_value
FROM detector_data
WHERE scope_id = 0 AND version_id = 0 AND config_id = 0;

SELECT data_id, COUNT(DISTINCT user_id) AS unique_users
FROM detector_comments
GROUP BY data_id;

SELECT AVG(value)
FROM detector_data
WHERE scope_id = 1 AND config_id = 1;

SELECT version_name, description 
FROM detector_data_versions 
WHERE version_id = 0;

SELECT comment_text
FROM detector_comments
WHERE comment_text LIKE '%re-run%';

SELECT config_id, AVG(value) AS average_value
FROM detector_data
GROUP BY config_id;

SELECT *
FROM detector_data
ORDER BY timestamp;

SELECT dc.config_name, dc.detector_type
FROM detector_configurations AS dc
JOIN detector_data AS dd ON dc.config_id = dd.config_id;

SELECT u.user_name, df.file_path, df.file_size, df.upload_date
FROM users u
JOIN data_files df ON u.user_id = df.data_id;

SELECT AVG(value) AS average_value
FROM detector_data
WHERE config_id = (SELECT config_id FROM detector_configurations WHERE config_name = 'Configuration B');

SELECT config_id, COUNT(*) AS total_records
FROM detector_data
GROUP BY config_id;
